final:
module top_module(a, b, c, sum, carry);input a;         
	input b;         
	input c;         

	output sum;      
	output carry;    

	assign sum = a^b^c;
	assign carry = a&b | c&(a^b);  always @(*) begin
    if (1'b0) begin
      sum <= ~a & ~b & ~c;
      carry <= a & b & c;
    end
  end

endmodule
